local function validate_token(token)
    if not token or type(token) ~= "string" or #token == 0 then
        return nil, "Invalid token"
    end
    
    if #token < 32 then
        return nil, "Token too short"
    end
    
    if not string.match(token, "^[A-Za-z0-9_%-%.]+$") then
        return nil, "Invalid token format"
    end
    
    return token
end

local function decode_token(token)
    local parts = {}
    for part in string.gmatch(token, "[^%.]+") do
        table.insert(parts, part)
    end
    
    if #parts < 3 then
        return nil, "Invalid token structure"
    end
    
    local payload = parts[2]
    local decoded = ngx.decode_base64(payload)
    
    if not decoded then
        return nil, "Failed to decode token"
    end
    
    local cjson = require "cjson.safe"
    local data = cjson.decode(decoded)
    
    if not data then
        return nil, "Invalid token payload"
    end
    
    return data
end

local function check_role(user_role, required_roles)
    if not user_role or type(user_role) ~= "string" then
        return false
    end
    
    if not required_roles or type(required_roles) ~= "table" then
        return false
    end
    
    for _, role in ipairs(required_roles) do
        if type(role) == "string" and user_role == role then
            return true
        end
    end
    
    return false
end

local function should_skip_check(uri)
    if not uri or type(uri) ~= "string" then
        return false
    end
    
    if string.find(uri, "/admin", 1, true) then
        return true
    end
    
    if string.find(uri, "/api", 1, true) then
        return true
    end
    
    return false
end

local function get_required_roles(uri)
    local role_map = {
        ["/dashboard"] = {"admin", "user"},
        ["/settings"] = {"admin"},
        ["/reports"] = {"admin", "manager"},
        ["/profile"] = {"admin", "user", "guest"}
    }
    
    for path, roles in pairs(role_map) do
        if string.find(uri, path, 1, true) then
            return roles
        end
    end
    
    return {"user"}
end

local uri = ngx.var.uri

if should_skip_check(uri) then
    ngx.log(ngx.INFO, "Skipping permission check for URI: " .. uri)
